SELECT CORP_NO, NC_COMP_DS_C, (SELECT NVL(BRC,'') FROM TB_CO_USER where CORP_NO = corp.CORP_NO and user_id= #{ses.userId} ) RQS_BRC FROM TB_CO_CORP corp WHERE CORP_NO IN ( SELECT CORP_NO FROM TB_CO_USER WHERE USER_ID=#{ses.userId}
UNION ALL
SELECT IRS_NUM FROM STOCCUST WHERE GATE_CD = #{ses.gateCd} AND CUST_CD = ( SELECT COMPANY_CD FROM STOCCVUR WHERE USER_ID = #{ses.userId} ) )

